CREATE TABLE "PRODUCT_ATTR" ("PRODUCT_TYPE" VARCHAR2(10), "PRODUCT_CODE" VARCHAR2(60), "ATTR_CODE" VARCHAR2(30), "ATTR_VALUE" VARCHAR2(50)) ;

CREATE TABLE "PRODUCT_DEF" ("PRODUCT_TYPE" VARCHAR2(10), "PRODUCT_CODE" VARCHAR2(60), "PRODUCT_NAME" VARCHAR2(256), "NOTE" VARCHAR2(2000), "HISTORY" VARCHAR2(2000), "MERGE_MODE" NUMBER(1,0) DEFAULT 0, "TRIGGER_RENT" NUMBER(1,0) DEFAULT 0, "TRIGGER_PRESENT" NUMBER(1,0) DEFAULT 0, "CARRYOVER_FLAG" NUMBER(1,0) DEFAULT 0) ;

