CREATE TABLE "PRODUCT_ELEMENT" ("PRODUCT_ELEMENT_TYPE" VARCHAR2(10), "PRODUCT_ELEMENT_CODE" VARCHAR2(60), "PRODUCT_ELEMENT_NAME" VARCHAR2(256), "NOTE" VARCHAR2(2000), "HISTORY" VARCHAR2(2000), "TRIGGER_RENT" NUMBER(1,0) DEFAULT 0, "MERGE_MODE" NUMBER(1,0) DEFAULT 0) ;

CREATE TABLE "PRODUCT_SERVICE_ATTR" ("PRODUCT_TYPE" VARCHAR2(10), "PRODUCT_CODE" VARCHAR2(60), "SERVICE_PLAN_TYPE" VARCHAR2(60), "SERVICE_PLAN_ID" NUMBER(6,0), "ATTR_CODE" VARCHAR2(60), "ATTR_VALUE" VARCHAR2(100), "ATTR_NAME" VARCHAR2(200)) ;

CREATE TABLE "PRODUCT_SERVICE_PLAN" ("PRODUCT_TYPE" VARCHAR2(10), "PRODUCT_CODE" VARCHAR2(60), "SERVICE_PLAN_TYPE" VARCHAR2(20), "SERVICE_PLAN_ID" NUMBER(6,0), "SHARE_SERVICE" VARCHAR2(10), "START_CYCLE" NUMBER(6,0) DEFAULT 200000, "END_CYCLE" NUMBER(6,0) DEFAULT 999999) ;

