CREATE TABLE "PRODUCT_USAGE_ATTR" ("PRODUCT_TYPE" VARCHAR2(10), "PRODUCT_CODE" VARCHAR2(60), "ENTITY_ID" NUMBER(18,0), "ATTR_ID" NUMBER(8,0), "SHARE_SERVICE" VARCHAR2(10), "LIMIT_TYPE" CHAR(1), "LIMIT_VALUE" NUMBER(10,0), "NOTE" VARCHAR2(100), "STDFREE_EXPR" VARCHAR2(64), "G_STDFREE_EXPR" VARCHAR2(128), "USAGE_CLASS" VARCHAR2(4), "USAGE_SUBCLASS" VARCHAR2(4), "USAGE_PRECEDENCE" NUMBER(4,0) DEFAULT 0) ;

CREATE TABLE "PROG_LICENSE_DEF" ("NODEID" NUMBER(2,0), "PROGNAME" VARCHAR2(64), "LICENSETYPE" VARCHAR2(64), "APPLYCODE" VARCHAR2(128), "AUTHCODE" VARCHAR2(256), "LICENSEVALUE" NUMBER(8,0)) ;

CREATE TABLE "Q2F_TASK_DEF" ("TASKID" NUMBER(10,0), "TASKNAME" VARCHAR2(128), "MAXEVENTCOUNT" NUMBER(9,0), "SLEEPSECONDS" NUMBER(9,0), "BATCHMAXCNT" NUMBER(9,0) DEFAULT 0) ;

CREATE TABLE "Q2F_TASK_ITEM" ("TASKID" NUMBER(10,0), "SUBID" NUMBER(10,0), "SUBNAME" VARCHAR2(128), "TRIMEVENTID" NUMBER(4,0), "SOURCETYPE" VARCHAR2(1) DEFAULT 's', "QUEUENAME" VARCHAR2(256), "FILEFORMAT" NUMBER(3,0), "MODULEID" NUMBER(16,0), "DELIMITER" VARCHAR2(10), "PROCESSMODULEID" NUMBER(10,0) DEFAULT 0, "FILEHEAD_EVENTID" NUMBER(5,0), "FILEBODY_EVENTID" NUMBER(5,0), "FILETAIL_EVENTID" NUMBER(5,0), "HEADTAIL_PROCESSSCHEMA" NUMBER(5,0), "FILTER_NONAME_ATTR" NUMBER(1,0) DEFAULT 0, "IS_ORDER_OUT" NUMBER(1,0) DEFAULT 0) ;

