CREATE TABLE "REFERRED_OBJECT" ("OBJECT_ID" NUMBER(4,0), "OBJECT_NAME" VARCHAR2(40), "ENTITY_ID" NUMBER(9,0), "ISONEINST" NUMBER(1,0), "ENTITY_TYPE" NUMBER(4,0)) ;

CREATE TABLE "REGION_ATTR" ("REGION_ID" NUMBER(4,0), "ATTR_ID" VARCHAR2(30), "VALUE_ORDER" NUMBER(4,0) DEFAULT 0, "ATTR_VALUE" VARCHAR2(50)) ;

CREATE TABLE "REGION_DEF" ("REGION_ID" NUMBER(4,0), "REGION_CODE" VARCHAR2(30), "REGION_TYPE" NUMBER(1,0), "REGION_NAME" NVARCHAR2(50), "NOTE" NVARCHAR2(200)) ;

CREATE TABLE "REGION_ENTITY_SCOPE" ("REGION_ID" NUMBER(4,0), "ENTITY_ID" NUMBER(4,0), "MAX_KEY_ID" NUMBER(13,0), "MIN_KEY_ID" NUMBER(13,0), "ENTITY_MAX" NUMBER(10,0), "STATIC_ATTR_MAX" NUMBER(10,0), "USAGE_ATTR_MAX" NUMBER(10,0), "BILLPLAN_ATTR_MAX" NUMBER(10,0), "STATIC_ATTR_PERCENT" NUMBER(2,0) DEFAULT 0, "STATIC_ATTR_AVG_LEN" NUMBER(6,0) DEFAULT 0) ;

CREATE TABLE "REGION_INDEX_SCOPE" ("REGION_ID" NUMBER(4,0), "ENTITY_ID" NUMBER(4,0), "INDEX_ID" NUMBER(4,0), "INDEX_MAX" NUMBER(10,0)) ;

CREATE TABLE "REGION_RECUPERATING_ENV_INFO" ("REGION" NUMBER(5,0), "DATABASE" VARCHAR2(100), "CDR_DBLINK" VARCHAR2(100), "HOST_ID" VARCHAR2(60), "PROC_COUNT" NUMBER(5,0) DEFAULT 1, "PROC_ID_LIST" VARCHAR2(1000), "LOG_FILE" VARCHAR2(100)) ;

