CREATE TABLE "REMIND_CONTROL_BATCH" ("REMIND_ENTRY_ID" NUMBER(2,0), "REMIND_SEQ" NUMBER(4,0), "BATCH_TYPE" NUMBER(1,0), "BATCH_ID" NUMBER(4,0) DEFAULT -1, "IS_DYNAMIC" NUMBER(1,0) DEFAULT 0, "STATUS_LOG_TYPE" NUMBER(2,0), "OUTPUT_TYPE" NUMBER(2,0) DEFAULT 1) ;

CREATE TABLE "REMIND_CONTROL_DEF" ("REMIND_ENTRY_ID" NUMBER(2,0), "REMIND_PARAM_ID" NUMBER(4,0), "REMIND_ENTRY_NAME" VARCHAR2(20), "NOTYFY_TYPE" NUMBER(2,0), "TRIGGER_TYPE" NUMBER(1,0), "TRIGGER_EVENT_ID" NUMBER(4,0), "CONDITION" VARCHAR2(256), "G_CONDITION" VARCHAR2(256), "REMIND_ENTITY" NUMBER(2,0) DEFAULT 1, "APPLY_METHOD" NUMBER(1,0) DEFAULT 8) ;

CREATE SEQUENCE  "SEQ_REFRESH_INDEX"  MINVALUE 1 MAXVALUE 999999999999999999 INCREMENT BY 1 START WITH 383163 CACHE 100 NOORDER  NOCYCLE ;

